from collections import defaultdict
from collections import OrderedDict as odict

def _load_choices(tokens):
    choices = defaultdict(dict)

    for val_id, frame, signal_name, values in tokens.get('VAL_', []):
        if not frame:
            continue

        od = odict((int(value[0]), NamedSignalValue(value[0], value[1])) for value in values)

        if not od:
            continue

        frame_id = int(frame[0])
        choices[frame_id][signal_name] = od

    return choices

