def set_registry(keys):
    mask = winreg.KEY_WOW64_64KEY | winreg.KEY_ALL_ACCESS if is_64bit() else winreg.KEY_ALL_ACCESS

    for key_name, (root_key, sub_key, value_name, value_type, value_data) in keys.items():
        try:
            key = winreg.CreateKeyEx(root_key, sub_key, 0, mask)
            winreg.SetValueEx(key, value_name, 0, value_type, value_data)
            winreg.CloseKey(key)
            logger.info(f"Registry: Successfully modified {key_name} key.")
        except OSError:
            logger.exception(f"Registry: Unable to modify {key_name} key.")

