def receiver(self):
    '''
    receive policy and value from neural network
    '''
    while not self.job_done:
        if self.pipe.poll(0.001):
            rets = self.pipe.recv()
        else:
            continue

        with self.q_lock:
            for k, (policy, value) in enumerate(rets):
                # logger.debug(f"NN ret, update tree buffer_history = {self.buffer_history}")
                self.executor.submit(self.update_tree, policy, value, self.buffer_history[k])

            self.buffer_planes = self.buffer_planes[k+1:]
            self.buffer_history = self.buffer_history[k+1:]

        self.run_lock.release()

