```python
def chunked_trees(self):
    """درخت وابستگی‌های جملات را برمی‌گرداند.

    Examples:
        >>> from hazm.Chunker import tree2brackets
        >>> tree2brackets(next(dadegan.chunked_trees()))
        '[این میهمانی NP] [به PP] [منظور آشنایی هم‌تیمی‌های او NP] [با PP] [غذاهای ایرانی NP] [ترتیب داده_شد VP] .'

    Yields:
        (str): درخت وابستگی‌های جملهٔ بعدی.
    """        
    for tree in self.trees():
        chunks = []
        for node in word_nodes(tree):
            n, ctag, rel, head, word_tag = node['address'], node['ctag'], node['rel'], node['head'], (node['word'], node['mtag'])
            item = word_tag
            appended = False
            if ctag in {'PREP', 'POSTP'}:
                for d in node_deps(node):
                    label = 'PP' if ctag != 'POSTP' else 'POSTP'
                    if d == n - 1 and isinstance(chunks[-1], Tree) and chunks[-1].label() == label:
                        chunks[-1].append(item)
                        appended = True
                if head == n - 1 and len(chunks) > 0 and isinstance(chunks[-1], Tree) and chunks[-1].label() == label:
                    chunks[-1].append(item)
                    appended = True
                if not appended:
                    chunks.append(Tree(label, [item]))
            elif ctag in {'PUNC', 'CONJ', 'SUBR', 'PART'}:
                if item[0] in {"'", '"', '(', ')', '{', '}', '[', ']', '-', '#', '«', '»'} and len(chunks) > 0 and isinstance(chunks[-1], Tree):
                    for l in chunks[-1].leaves():
                        if l[1] == item[1]:
                            chunks[-1].append(item)
                            appended = True
                            break
                if not appended:
                    chunks.append(item)
            elif ctag in {'N', 'PREM', 'ADJ', 'PR', 'ADR', 'PRENUM', 'IDEN', 'POSNUM', 'SADV'}:
                if rel in {'MOZ', 'NPOSTMOD'}:
                    if len(chunks) > 0:
                        if isinstance(chunks[-1], Tree):
                            j = n - len(chunks[-1].leaves())
                            chunks[-1].append(item)
                        else:
                            j = n - 1
                            chunks.append(Tree('NP', [chunks.pop(), item]))
                        while j > head:
                            leaves = chunks.pop().leaves()
                            if len(chunks) < 1:
                                chunks.append(Tree('NP', leaves))
                            elif isinstance(chunks[-1], Tree):
                                j -= len(chunks[-1])
                                for l in leaves:
                                    chunks[-1].append(l)
                            else:
                                leaves.insert(0, chunks.pop())
                                chunks.append(Tree('NP', leaves))
                            j -= 1
                        continue
                elif rel == 'POSDEP' and tree.nodes[head]['rel'] in {'NCONJ', 'AJCONJ'}:
                    conj = tree.nodes[head]
                    if tree.nodes[conj['head']]['rel'] in {'MOZ', 'NPOSTMOD', 'AJCONJ', 'POSDEP'}:
                        label, leaves, j = 'NP', [item], n - 1
                        while j >= conj['head']:
                            if isinstance(chunks[-1], Tree):
                                j -= len(chunks[-1].leaves())
                                label = chunks[-1].label()
                                leaves = chunks.pop().leaves() + leaves
                            else:
                                leaves.insert(0, chunks.pop())
                                j -= 1
                        chunks.append(Tree(label, leaves))
                        appended = True
                elif head == n - 1 and len(chunks) > 0 and isinstance(chunks[-1], Tree) and chunks[-1].label() != 'PP':
                    chunks[-1].append(item)
                    appended = True
                elif rel == 'AJCONJ' and tree.nodes[head]['rel'] in {'NPOSTMOD', 'AJCONJ'}:
                    np_nodes = [item]
                    label = 'ADJP'
                    i = n - head
                    while i > 0:
                        if isinstance(chunks[-1], Tree):
                            label = chunks[-1].label()
                            leaves = chunks.pop().leaves()
                            i -= len(leaves)
                            np_nodes = leaves + np_nodes
                        else:
                            i -= 1
                            np_nodes.insert(0, chunks.pop())
                    chunks.append(Tree(label, np_nodes))
                    appended = True
                elif ctag == 'ADJ' and rel == 'POSDEP' and tree.nodes[head]['ctag'] != 'CONJ':
                    np_nodes = [item]
                    i = n - head
                    while i > 0:
                        label = 'ADJP'
                        if isinstance(chunks[-1], Tree):
                            label = chunks[-1].label()
                            leaves = chunks.pop().leaves()
                            i -= len(leaves)
                            np_nodes = leaves + np_nodes
                        else:
                            i -= 1
                            np_nodes.insert(0, chunks.pop())
                    chunks.append(Tree(label, np_nodes))
                    appended = True
                for d in node_deps(node):
                    if d == n - 1 and isinstance(chunks[-1], Tree) and chunks[-1].label() != 'PP' and not appended:
                        label = chunks[-1].label()
                        if rel == 'ADV':
                            label = 'ADVP'
                        elif label in {'ADJP', 'ADVP'}:
                            label = 'NP' if ctag == 'N' else 'ADJP'
                        leaves = chunks.pop().leaves()
                        leaves.append(item)
                        chunks.append(Tree(label, leaves))
                        appended = True
                    elif tree.nodes[d]['rel'] == 'NPREMOD' and not appended:
                        np_nodes, i = [item], n - d
                        while i > 0:
                            if isinstance(chunks[-1], Tree):
                                leaves = chunks.pop().leaves()
                                i -= len(leaves)
                                np_nodes = leaves + np_nodes
                            else:
