                        appended = True
                        break
                if not appended:
                    chunks.append(Tree('VP', [item]))
            elif ctag == 'PSUS':
                chunks.append(Tree('ADVP' if rel == 'ADV' else 'VP', [item]))
            elif ctag in {'ADV', 'SADV'}:
                appended = False
                for d in node_deps(node):
                    if d == n - 1 and isinstance(chunks[-1], Tree):
                        leaves = chunks.pop().leaves()
